import java.util.*; import java.util.stream.*;
public class EmployeeReportGenerator { static class Employee { String name, department; double salary; Employee(String name, String department, double salary) { this.name = name; this.department = department; this.salary = salary; } public String toString() { return name + " " + salary; } } public static void main(String[] args) { List<Employee> employees = Arrays.asList(new Employee("Anu", "IT", 70000), new Employee("Bala", "HR", 45000), new Employee("Charu", "IT", 80000), new Employee("Devi", "Sales", 52000)); List<String> highEarners = employees.stream().filter(e -> e.salary > 50000).sorted(Comparator.comparingDouble((Employee e) -> e.salary).reversed()).map(e -> e.name + " - " + e.department).limit(3).collect(Collectors.toList()); Map<String, Long> departmentCount = employees.stream().collect(Collectors.groupingBy(e -> e.department, Collectors.counting())); System.out.println("High earners: " + highEarners); System.out.println("Department count: " + departmentCount); } }
